+@page "/board"
+@rendermode InteractiveServer
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h2 class="mb-3">Project Board</h2>
+
+@if (_loading)
+{
+    <div class="d-flex justify-content-center my-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (_errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @_errorMessage
+        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
+    </div>
+}
+else
+{
+    <!-- Stats Bar -->
+    <div class="row g-2 mb-3">
+        <div class="col">
+            <div class="card text-center">
+                <div class="card-body py-2">
+                    <div class="fw-bold">Total</div>
+                    <div class="fs-5">@_allTasks.Count</div>
+                </div>
+            </div>
+        </div>
+        @foreach (var col in _columns)
+        {
+            <div class="col">
+                <div class="card text-center">
+                    <div class="card-body py-2">
+                        <div class="fw-bold">@col</div>
+                        <div class="fs-5">@GetTasksForColumn(col).Count</div>
+                    </div>
+                </div>
+            </div>
+        }
+        <div class="col">
+            <div class="card text-center">
+                <div class="card-body py-2">
+                    <div class="fw-bold">Overdue</div>
+                    <div class="fs-5 text-danger">@_allTasks.Count(t => t.DueDate < DateTime.Today)</div>
+                </div>
+            </div>
+        </div>
+    </div>
+
+    <!-- Search Bar -->
+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title..."
+               @bind="_searchText" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban Columns -->
+    <div class="row g-3">
+        @for (var i = 0; i < _columns.Length; i++)
+        {
+            var colIndex = i;
+            var colName = _columns[colIndex];
+            var colTasks = GetFilteredTasksForColumn(colName);
+
+            <div class="col-md-4">
+                <div class="card">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <strong>@colName</strong>
+                        <span class="badge bg-secondary">@colTasks.Count</span>
+                    </div>
+                    <div class="card-body" style="min-height: 200px;">
+                        @foreach (var task in colTasks)
+                        {
+                            <div class="card mb-2">
+                                <div class="card-body p-2">
+                                    <div class="fw-bold">@task.Title</div>
+                                    <div class="text-muted small">@task.Assignee</div>
+                                    <div class="d-flex justify-content-between align-items-center mt-1">
+                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
+                                        <span class="small text-muted">@task.DueDate.ToString("MMM dd")</span>
+                                    </div>
+                                    <div class="d-flex justify-content-between mt-2">
+                                        @if (colIndex > 0)
+                                        {
+                                            <button class="btn btn-sm btn-outline-secondary"
+                                                    disabled="@_movingTaskId.HasValue"
+                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex - 1])">
+                                                &larr; Move Left
+                                            </button>
+                                        }
+                                        else
+                                        {
+                                            <span></span>
+                                        }
+                                        @if (colIndex < _columns.Length - 1)
+                                        {
+                                            <button class="btn btn-sm btn-outline-secondary"
+                                                    disabled="@_movingTaskId.HasValue"
+                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[colIndex + 1])">
+                                                Move Right &rarr;
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (_addingToColumn == colName)
+                        {
+                            <div class="card border-primary mb-2">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1"
+                                           placeholder="Title" @bind="_newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1"
+                                           placeholder="Assignee" @bind="_newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-2"
+                                           @bind="_newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-sm btn-primary" disabled="@_saving"
+                                                @onclick="() => SaveNewTaskAsync(colName)">
+                                            @(_saving ? "Saving..." : "Save")
+                                        </button>
+                                        <button class="btn btn-sm btn-outline-secondary"
+                                                disabled="@_saving" @onclick="CancelAdd">
+                                            Cancel
+                                        </button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer">
+                        <button class="btn btn-sm btn-outline-primary w-100"
+                                @onclick="() => StartAdd(colName)">
+                            + Add Task
+                        </button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> _allTasks = new();
+    private bool _loading = true;
+    private string? _errorMessage;
+    private string _searchText = string.Empty;
+
+    // Move state
+    private int? _movingTaskId;
+
+    // Add-task form state
+    private string? _addingToColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+    private bool _saving;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        _loading = true;
+        _errorMessage = null;
+        try
+        {
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetTasksForColumn(string status)
+        => _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredTasksForColumn(string status)
+        => _allTasks
+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(_searchText) ||
+                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        _movingTaskId = taskId;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var task = _allTasks.FirstOrDefault(t => t.Id == taskId);
+            if (task is not null)
+            {
+                _allTasks[_allTasks.IndexOf(task)] = task with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _movingTaskId = null;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        _addingToColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd()
+    {
+        _addingToColumn = null;
+    }
+
+    private async Task SaveNewTaskAsync(string column)
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+            return;
+
+        _saving = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
+            // If the service returns the task in a default status, update it to the target column
+            if (created.Status != column)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, column);
+                created = created with { Status = column };
+            }
+            _allTasks.Add(created);
+            _addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
+

